// src/controllers/StudyMethodController.js
import StudyMethodService from '../services/StudyMethodService';

const StudyMethodController = {
  async loadMethods(filters, setMethods, setLoading, toast) {
    setLoading(true);
    try {
      const data = await StudyMethodService.getAllMethods(filters);
      setMethods(data);
    } catch (error) {
      toast.error('Erro ao carregar métodos de estudo.');
    } finally {
      setLoading(false);
    }
  },

  async handleCreate(formData, userId, setMethods, closeModal, toast) {
    try {
      const newMethod = await StudyMethodService.createMethod(formData, userId);
      setMethods(prev => [newMethod, ...prev]);
      toast.success('Método criado com sucesso!');
      closeModal();
    } catch (error) {
      toast.error(error.message || 'Erro ao criar método.');
    }
  },

  async handleUpdate(id, formData, setMethods, closeModal, toast) {
    try {
      const updated = await StudyMethodService.updateMethod(id, formData);
      setMethods(prev => prev.map(m => (m.id === id ? updated : m)));
      toast.success('Método atualizado!');
      closeModal();
    } catch (error) {
      toast.error(error.message || 'Erro ao atualizar método.');
    }
  },

  async handleDelete(id, setMethods, toast) {
    try {
      await StudyMethodService.deleteMethod(id);
      setMethods(prev => prev.filter(m => m.id !== id));
      toast.success('Método removido.');
    } catch (error) {
      toast.error(error.message || 'Erro ao remover método.');
    }
  },

  getCategories() {
    return StudyMethodService.getCategories();
  },

  getCategoryLabel(value) {
    return StudyMethodService.getCategoryLabel(value);
  }
};

export default StudyMethodController;
